#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-03-24

# Test parse-frontmatter.js — especially multiline scalar support
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="${CLAUDE_PROJECT_DIR:-$(cd "$SCRIPT_DIR/../.." && pwd)}"
PARSER="$PROJECT_ROOT/scripts/lib/parse-frontmatter.js"

RED='\033[0;31m'
GREEN='\033[0;32m'
NC='\033[0m'

PASS=0
FAIL=0

pass() { echo -e "  ${GREEN}✓${NC} $1"; PASS=$((PASS + 1)); }
fail() { echo -e "  ${RED}✗${NC} $1"; FAIL=$((FAIL + 1)); }

# Helper: parse frontmatter and extract a field
parse_field() {
  local content="$1"
  local field="$2"
  node -e "
    const { parseYamlFrontmatter } = require('$PARSER');
    const result = parseYamlFrontmatter(\`$content\`);
    const val = result.frontmatter['$field'];
    if (val === undefined) process.exit(1);
    console.log(typeof val === 'string' ? val : JSON.stringify(val));
  "
}

echo "============================================================================"
echo "  parse-frontmatter.js Tests"
echo "============================================================================"
echo ""

# Test 1: Simple key-value
echo "▶ Test 1: Simple key-value"
result=$(parse_field '---
name: my-skill
version: 1.0.0
---
body' "name")
[[ "$result" == "my-skill" ]] && pass "Simple string value" || fail "Expected 'my-skill', got '$result'"

# Test 2: Quoted string
echo "▶ Test 2: Quoted string"
result=$(parse_field '---
description: "A quoted description with spaces"
---
body' "description")
[[ "$result" == "A quoted description with spaces" ]] && pass "Quoted string" || fail "Expected unquoted, got '$result'"

# Test 3: Inline array
echo "▶ Test 3: Inline array"
result=$(parse_field '---
tags: [a, b, c]
---
body' "tags")
[[ "$result" == '["a","b","c"]' ]] && pass "Inline array" || fail "Expected array, got '$result'"

# Test 4: Boolean values
echo "▶ Test 4: Booleans"
result=$(parse_field '---
user-invocable: true
---
body' "user-invocable")
[[ "$result" == "true" ]] && pass "Boolean true" || fail "Expected true, got '$result'"

# Test 5: Multi-line array (- items)
echo "▶ Test 5: Multi-line array"
result=$(parse_field '---
tools:
  - Read
  - Write
  - Edit
---
body' "tools")
[[ "$result" == '["Read","Write","Edit"]' ]] && pass "Multi-line array" || fail "Expected array, got '$result'"

# Test 6: >- folded scalar (THE BUG WE FIXED)
echo "▶ Test 6: >- folded scalar"
result=$(parse_field '---
description: >-
  This is a long description
  that spans multiple lines
  and should be joined.
name: after
---
body' "description")
if [[ "$result" == *"This is a long description"* ]] && [[ "$result" == *"that spans multiple lines"* ]]; then
  pass ">- folded scalar joins lines"
else
  fail "Expected joined string, got '$result'"
fi

# Test 7: >- doesn't eat the next key
echo "▶ Test 7: >- stops at next key"
result=$(parse_field '---
description: >-
  Multi line desc.
name: my-skill
---
body' "name")
[[ "$result" == "my-skill" ]] && pass ">- stops at next key" || fail "Expected 'my-skill', got '$result'"

# Test 8: | literal scalar
echo "▶ Test 8: | literal scalar"
result=$(parse_field '---
description: |
  Literal block scalar
  preserves newlines.
name: test
---
body' "description")
[[ -n "$result" ]] && [[ "$result" == *"Literal block scalar"* ]] && pass "| literal scalar" || fail "Expected content, got '$result'"

# Test 9: > folded scalar (no dash)
echo "▶ Test 9: > folded scalar"
result=$(parse_field '---
description: >
  Folded without dash
  also works.
name: test
---
body' "description")
[[ "$result" == *"Folded without dash"* ]] && pass "> folded scalar" || fail "Expected content, got '$result'"

# Test 10: Description length check (not 2 chars)
echo "▶ Test 10: >- description length > 2"
result=$(parse_field '---
description: >-
  json-render component catalog patterns for AI-safe generative UI.
  Define Zod-typed catalogs that constrain what AI can generate.
name: json-render-catalog
---
body' "description")
len=${#result}
[[ "$len" -gt 50 ]] && pass "Description length $len chars (not 2)" || fail "Description only $len chars — parser still broken"

echo ""
echo "============================================================================"
echo "  Results: $PASS passed, $FAIL failed"
echo "============================================================================"

[[ "$FAIL" -eq 0 ]] || exit 1
